import type { NextPage } from "next";
import Head from "next/head";
import Image from "next/image";
import { signOut, useSession } from "next-auth/react";
import { useRouter } from "next/router";
import { useEffect } from "react";

const ProfilePage: NextPage = () => {
  const { data: sessionData, status } = useSession();
  const router = useRouter();

  // Redirect to home if not authenticated
  useEffect(() => {
    if (status === "unauthenticated") {
      void router.push("/");
    }
  }, [status, router]);

  if (status === "loading") {
    return <p>Loading...</p>;
  }

  if (!sessionData) {
    return null;
  }

  return (
    <>
      <Head>
        <title>Profile – Create T3 App</title>
        <meta name="description" content="Your GitHub profile" />
        <link rel="icon" href="/favicon.ico" />
      </Head>
      <main>
        <h1>Your Profile</h1>
        <div>
          {sessionData.user?.image && (
            <Image
              src={sessionData.user.image}
              alt={`${sessionData.user.name ?? "User"}'s avatar`}
              width={80}
              height={80}
              style={{ borderRadius: "50%" }}
            />
          )}
          <p>
            <strong>Name:</strong> {sessionData.user?.name ?? "Unknown"}
          </p>
          {sessionData.user?.email && (
            <p>
              <strong>Email:</strong> {sessionData.user.email}
            </p>
          )}
          <p>
            <strong>User ID:</strong> {sessionData.user?.id}
          </p>
        </div>
        <button onClick={() => signOut({ callbackUrl: "/" })}>Sign out</button>
      </main>
    </>
  );
};

export default ProfilePage;

