import { createProtectedRouter } from "./protected-router";

// Example router with queries that can only be hit if the user requesting is signed in.
// The session on the context includes the GitHub user's name and avatar image.
export const profileRouter = createProtectedRouter().query("getProfile", {
  resolve({ ctx }) {
    return {
      id: ctx.session.user.id,
      name: ctx.session.user.name,
      email: ctx.session.user.email,
      // GitHub avatar URL is stored in session.user.image by the GitHub provider
      image: ctx.session.user.image,
    };
  },
});

